using backend.Models;

namespace backend.Database
{
        // Responsible for seeding initial data into the database (like default brands).
    public static class DbInitializer
    {
        public static void Initialize(TourbillonContext context)
        {
        // Skip seeding if brands already exist in the database
            if (context.Brands.Any()) return; // Already seeded

            // List of initial brands to seed

            // Command to delete and update db
            // dotnet ef database drop --force && dotnet ef database update
            var brands = new List<Brand>
            {
                new Brand { Name = "Patek Philippe", Description = "Patek Philippe is the very definition of prestige in watchmaking – a family-owned Geneva manufacture regarded by many as the most illustrious of all Swiss watch brands. Established in 1839 by Polish nobleman Antoine Norbert de Patek and later joined by French watchmaker Adrien Philippe, the company has, for over 180 years, been synonymous with uncompromising quality, tradition, and innovation. Patek Philippe’s legacy is built on a philosophy of lifelong value and generational craftsmanship; their famous adage, “You never actually own a Patek Philippe. You merely look after it for the next generation,” underlines the enduring significance and heirloom quality of these timepieces. Each watch is created in-house – from movements to cases – and hand-finished to the finest degree, often bearing the Patek Philippe Seal which signifies a higher standard than even traditional Geneva criteria. Renowned for producing some of the most complicated mechanical watches in the world, Patek Philippe has continually pushed horological boundaries while maintaining a classically elegant style that transcends eras. Throughout its history, Patek Philippe has introduced landmark timepieces that have become icons of style and ingenuity. The Calatrava, born in the 1930s, remains an archetype of the perfect dress watch with its pure lines and timeless dial. In 1976, Patek launched the Nautilus – a luxury sports watch in steel – which broke the mold and today stands as one of the most coveted watches globally for its blend of casual sophistication and fine mechanics. The brand’s mastery of grand complications is unparalleled: from the perpetual calendar chronographs of the 1940s (like the References 1518 and 2499, treasured by collectors) to minute repeaters, celestial charts, and split-second chronographs. Indeed, Patek Philippe’s watches have set records at auctions, underscoring their rarity and enduring appeal. Despite technical achievements, Patek’s design language remains reserved and refined, appealing to those who appreciate subtlety and tradition. To wear a Patek Philippe is to partake in a legacy of horological excellence passed down through generations – an investment in artistry, innovation, and enduring value that few other names can match.", Image = "patekphilipe.png" },
               
                new Brand { Name = "Vacheron Constantine", Description = "Vacheron Constantin stands at the pinnacle of haute horlogerie as one of the world’s oldest and most venerated watchmakers. Founded in Geneva in 1755, it holds an uninterrupted history of over 265 years, earning the title of the oldest continuously operating watch manufacturer. Such heritage is palpable in every Vacheron Constantin creation – each watch is a testament to generations of Swiss watchmaking artistry and tradition. The maison’s philosophy, encapsulated by its long-standing motto “Faire mieux si possible, ce qui est toujours possible” (“Do better if possible, and that is always possible”), speaks to an endless pursuit of perfection. Vacheron Constantin has been responsible for technical and artistic achievements that shaped horological history, from crafting some of the first complications in the 18th century to holding recent records for the most complex mechanical watches ever made. Each timepiece from this esteemed house is crafted with exquisite attention to detail, often featuring hand-guilloché dials, intricate engravings, and beautifully finished in-house movements that are as breathtaking to admire as they are precise in timekeeping. Known for its refined aesthetic and mechanical excellence, Vacheron Constantin has produced numerous iconic models. The Patrimony and Traditionnelle lines, for example, showcase classic round watches of timeless elegance, often housing high complications like perpetual calendars and minute repeaters finished to the Geneva Seal standard. In sports luxury, the Overseas collection combines technical robustness with the brand’s signature finesse, catering to modern travelers without sacrificing craftsmanship. Vacheron is also acclaimed for its one-of-a-kind grand complications (like the reference 57260 pocket watch with 57 complications, an astounding feat of micromechanics) and its historic pieces coveted by royalty and collectors. For the sophisticated buyer, a Vacheron Constantin timepiece represents the ultimate marriage of heritage and horological artistry – a legacy on the wrist that whispers of Geneva’s rich watchmaking pedigree.", Image = "vacheronconstantine.png" },

                new Brand { Name = "Audemars Piguet", Description = "Audemars Piguet is an icon of Swiss haute horlogerie, revered for its blend of tradition, innovation, and bold design. Founded in 1875 in the Vallée de Joux by Jules Louis Audemars and Edward Auguste Piguet, Audemars Piguet remains one of the few great watchmakers still in the hands of its founding families. This independence has fostered an unwavering dedication to horological excellence and avant-garde creativity. With a rich history of crafting high-complication timepieces – from minute repeaters and perpetual calendars to tourbillons – Audemars Piguet built its name among the “Holy Trinity” of Swiss watchmakers, alongside Patek Philippe and Vacheron Constantin. Every AP timepiece showcases exceptional mechanical artistry, finished to exacting standards in Le Brassus. Yet the brand is equally celebrated for breaking conventions: it consistently pushes the boundaries of design and engineering to redefine what a luxury watch can be. In 1972, Audemars Piguet revolutionized the industry with the Royal Oak, a luxury sports watch that dared to combine steel, an octagonal bezel secured by visible gold screws, and an integrated bracelet – all conceived by legendary designer Gérald Genta. Initially audacious, the Royal Oak is now an undisputed icon, symbolizing the brand’s pioneering spirit. Its success spawned variations like the larger, more aggressive Royal Oak Offshore in the 1990s and the contemporary Code 11.59 collection, which showcases AP’s modern approach to form and function. Beyond design, Audemars Piguet is esteemed for the impeccable quality of its movements and decorations – from the hand-polished bevels to the intricate “tapisserie” dials that have become a signature. Whether it’s a classic Jules Audemars dress watch housing a tourbillon or a cutting-edge Royal Oak Concept piece, Audemars Piguet’s creations offer a dynamic mix of heritage and innovation. For the luxury connoisseur, an Audemars Piguet on the wrist signifies membership in a rarified club where artistry meets daring vision – truly, it is a brand that “masters the rules and then breaks them” in the pursuit of watchmaking greatness.", Image = "audemarspiguet.png" },

                new Brand { Name = "Jaeger-LeCoultre", Description = "Jaeger-LeCoultre is a storied Swiss manufacture often hailed as “the watchmaker’s watchmaker” – a tribute to its unmatched technical prowess and its role as a movement supplier to other top marques. Founded in 1833 by Antoine LeCoultre in the Vallée de Joux, Jaeger-LeCoultre has cultivated nearly two centuries of continuous innovation, quietly shaping the course of haute horlogerie. The brand has developed over 1,200 different mechanical calibers – an astounding number – and earned about 400 patents, reflecting an unwavering commitment to quality and invention in automatic watchmaking. From pioneering the millionometer in 1844 (an instrument for measuring microns) to inventing keyless winding systems and ultra-thin movements, the “Grande Maison” has a legacy of technical firsts. Each Jaeger-LeCoultre timepiece is made in-house in Le Sentier, where the manufacture integrates the full range of crafts under one roof – from movement design and enamel artistry to case polishing – a rare capability even among luxury brands. While rich in engineering, Jaeger-LeCoultre’s watches also exude timeless style and creativity. Its most emblematic model, the Reverso, introduced in 1931, exemplifies Art Deco elegance and ingenuity: originally designed for British polo players, its rectangular case swivels to protect the dial, offering both practicality and a canvas for personalization. In the Reverso and beyond, JLC’s designs balance refinement with a quiet complexity. The Master Control series, for instance, showcases the brand’s classic round watches, each subjected to 1,000 hours of testing for reliability. High complications like the Duomètre (with its dual-wing movement architecture) and the Gyrotourbillon (a multi-axis tourbillon marvel) demonstrate Jaeger-LeCoultre’s inventive spirit in pushing mechanical frontiers without forsaking traditional hand-finishing and decor. Despite crafting complications for the most discerning collectors, Jaeger-LeCoultre watches remain understated, often reserved for true connoisseurs who recognize the depth behind the dial. For the Tourbillon shopper seeking substance and heritage, Jaeger-LeCoultre offers the reassurance of a manufacture that has long been the industry’s hidden hero – delivering peerless craftsmanship, innovation, and an elegance that endures across generations.", Image = "jaegerlecoultre.png" },

                new Brand { Name = "A. Lange & Söhne", Description = "A. Lange & Söhne represents the pinnacle of German watchmaking, a brand reborn from history to rival the finest Swiss maisons with its own Teutonic flair. Originally founded in 1845 by Ferdinand Adolph Lange in the Saxon town of Glashütte, Lange established a tradition of precision engineering and sublime craftsmanship that elevated German horology to world renown. Early Lange pocket watches were prized by kings and connoisseurs for their accuracy and quality. The upheavals of the 20th century – including World War II and subsequent Soviet-era nationalization – silenced the brand for decades, but following German reunification in 1990, Walter Lange (great-grandson of the founder) resurrected A. Lange & Söhne with spectacular success. In 1994, the brand unveiled its first modern collection, led by the Lange 1, and immediately reestablished itself as a leader in haute horlogerie. Today, Lange’s timepieces are once again crafted in Glashütte and adhere to the original ethos: unparalleled technical mastery combined with an understated, elegant aesthetic. Each watch is built not just as an instrument, but as an objet d’art – with the signature three-quarter plate, blued screws, gold chatons, and hand-engraved balance cock showcasing the house’s commitment to traditional hand-finishing and detail. Owning an A. Lange & Söhne is akin to owning a piece of horological art. The Lange 1, with its asymmetrical dial and outsize date display, has become a modern icon, symbolizing the brand’s blend of innovation and respect for heritage. The 1815 collection (named after Ferdinand A. Lange’s birth year) pays tribute to classical watchmaking codes, often featuring complications like chronographs or tourbillons executed with Teutonic precision. Lange’s technical virtuosity shines in masterpieces such as the Datograph – revered as one of the finest chronograph movements ever made – and the Zeitwerk, which displays time numerically via jumping discs in a bold reimagining of the mechanical watch. Despite the complexity of its movements (which often incorporate multiple complications and patented mechanisms), Lange maintains an air of quiet luxury; cases of precious metals and solid silver dials are finished to perfection but are never flamboyant. This refined approach appeals to true enthusiasts. For a high-end collector, an A. Lange & Söhne watch offers a distinctive appeal: the legacy of Saxon innovation, immaculate craftsmanship, and a certain exclusivity – as the manufacture produces only a few thousand pieces a year. It is the epitome of “German engineering” applied to fine watchmaking, yielding a timepiece of both soul and substance, to be cherished for a lifetime and beyond.", Image = "alangesohne.png" },
               
                new Brand { Name = "Glashütte Original", Description = "Glashütte Original carries the torch of Germany’s rich Saxon watchmaking tradition, offering timepieces that blend historic heritage with modern ingenuity. The brand’s roots stretch back to 1845, when master watchmakers like Ferdinand Adolph Lange and others established Glashütte, a small town in Saxony, as the epicenter of German horology. In the aftermath of World War II, the region’s watch companies were unified under a state-owned entity during the East German era (GUB – Glashütter Uhrenbetriebe). With German reunification, this entity was privatized in 1994 as Glashütte Original, ensuring that the accumulated expertise and traditions of 150 years would live on in a contemporary manufacture. Now part of the Swatch Group, Glashütte Original is a fully integrated maker that proudly produces up to 95% of its own components in-house – even crafting its own dials – a testament to self-reliance and craft. Each watch is assembled in Glashütte by skilled artisans, many of whom were trained locally, preserving the region’s lineage of fine watchmaking. The result is a collection of mechanical watches that honor classical techniques (such as the famed Glashütte three-quarter plate and swan-neck regulator) while embracing modern precision and style. Glashütte Original’s timepieces are distinguished by their Germanic elegance and attention to detail. The Senator collection, for example, showcases classic designs influenced by vintage observatory chronometers – with clean layouts, blued hands, and complications like panorama date displays, moonphases, or perpetual calendars executed with restraint and clarity. In contrast, the Pano series offers a contemporary twist: off-center dials and asymmetrical arrangements that highlight the depth of in-house movements, visible through sapphire casebacks, complete with traditional elements like blued screws and hand-engraved decorations. Whether it’s the retro-inspired Sixties models (with funky dials recalling 1960s Glashütte styles) or the sporty SeaQ dive watches (reviving a 1970s design with modern engineering), the brand infuses each piece with a uniquely Saxon character. Hallmark features such as the double-disc big date (Panoramadatum) and superb dial finishes (sunbursts, dégradé colors, or grainé textures) set these watches apart from their Swiss counterparts, offering a fresh yet historically grounded alternative. For the high-end shopper, a Glashütte Original watch delivers the best of both worlds: authentic heritage dating to the 19th century and the confidence of German-made quality under a modern global luxury group. It’s an invitation to wear a piece of living history – where every glance at the wrist reflects generations of dedication to craft and innovation.", Image = "glashutteoriginal.png" },
               
                new Brand { Name = "F.P.Journe", Description = "F.P. Journe is a beacon of contemporary haute horlogerie – an independent Swiss atelier where the vision of one man, François-Paul Journe, has created an extraordinary legacy of innovation and artistry. Founded in 1999 in Geneva, the brand quickly attained cult status among collectors for its unique blend of 18th-century inspired craftsmanship and ground-breaking mechanical inventions. Every F.P. Journe dial bears the inscription “Invenit et Fecit,” Latin for “(He) invented it and made it,” which is the company’s motto and ethos. It signifies that each watch is conceived and built in-house, often by Journe’s own hand, reflecting an auteur approach to watchmaking rarely seen today. The result is an array of timepieces that are as technically fascinating as they are aesthetically distinctive. Journe’s watches typically feature beautiful gold movements, a signature warm hue visible through sapphire casebacks, and dials with an unmistakable layout and font that speak to classic French chronometer design. Yet beneath the traditional styling lie mechanical masterpieces that have earned F.P. Journe the industry’s highest accolades (including multiple “Aiguille d’Or” grand prizes at the Geneva Grand Prix). What sets F.P. Journe apart are the imaginative complications and technical solutions born from François-Paul’s fertile mind. His very first production model, the Tourbillon Souverain (1999), was the world’s first wristwatch tourbillon with a remontoir d’égalité (constant-force device), achieving remarkable accuracy by equalizing the power delivery to the escapement. In 2000, Journe debuted the Chronomètre à Résonance, the only wristwatch to harness the natural phenomenon of resonance with two closely positioned balance wheels synchronizing to improve stability. These trailblazing watches – along with later creations like the Octa automatic series offering lengthy power reserves and slim profiles, the Centigraphe’s lightning-fast chronograph, and the elegant Sonnerie minute repeater – illustrate the brand’s genius for solving complex horological challenges in novel ways. Despite their intricacy, F.P. Journe watches maintain a wearable, 38–40mm size and a refined, coherent design language that makes them as suitable for daily wear as they are for admiration under a loupe. Production is extremely limited, with only a few hundred pieces leaving the workshop each year, conferring exclusivity on each reference. For the high-end collector, an F.P. Journe timepiece represents the ultimate confluence of innovation, authenticity, and artistry. It’s not just a luxury watch – it’s the embodiment of a living watchmaker’s uncompromised passion, a piece of modern horological history destined to be treasured for generations.", Image = "fpjourne.png" },
               
                new Brand { Name = "Greubel Forsey", Description = "Greubel Forsey stands at the apex of modern watchmaking artistry – a horological think-tank producing some of the most complex and exquisitely finished timepieces in the world. Founded in 2004 by Frenchman Robert Greubel and Englishman Stephen Forsey, this independent maison has redefined haute horlogerie through its uncompromising focus on innovation, technical complexity, and hand-craftsmanship. Greubel Forsey produces fewer than 100 watches per year, each one an extraordinary mechanical sculpture designed for the connoisseur who seeks the absolute pinnacle of independent watchmaking. At the heart of the brand’s philosophy is a drive to improve chronometric performance and expand the possibilities of traditional complications – most notably, the tourbillon. Greubel Forsey is famous for its multi-axis tourbillon inventions, which aim to average out gravitational errors in multiple dimensions. These tourbillon systems (such as the Double Tourbillon 30°, Quadruple Tourbillon, and 24-Second Tourbillon) are marvels of micro-engineering, often showcased front and center in deeply architectural dials and movements that offer a three-dimensional visual feast. Every component, down to the smallest wheel or screw, is finished by hand to a peerless standard – black polishing, mirror anglage, perlage, and straight graining are executed with obsessive perfection, often under microscope, consuming labor hours unimaginable in typical watch manufacture. The result is that each Greubel Forsey watch is not only a timekeeper but a work of art, radiating a jewel-like quality and depth of detail that few others can match. Despite their high complexity, Greubel Forsey’s timepieces are engineered with a clear purpose and are surprisingly legible and robust in construction. Their designs often feature asymmetrical cases or pronounced domes of sapphire to accommodate the lofty mechanisms. Signature pieces include the GMT Earth, which incorporates a rotating miniature globe as a second time zone indicator – blending practical function with artistic flair – and the Balancier series, which highlights an oversized inclined balance wheel, demonstrating that even timekeeping regulation can be an art form. Greubel Forsey’s recent creations, like the Hand Made 1, push boundaries even further by achieving 95% of components fabricated by hand, essentially resurrecting Old World watchmaking techniques for the modern era. Owning a Greubel Forsey is a privilege reserved for a very select few; these watches often cost in the six to seven figures and are made in vanishingly small numbers, with some references limited to single-digit pieces. For the seasoned collector, a Greubel Forsey represents the ultimate convergence of innovation and tradition – a timepiece where every glance reveals another layer of technical genius or artisanal beauty. In the context of Tourbillon’s offerings, Greubel Forsey is the crowning jewel of independent horology: a brand that doesn’t just make watches, but rather, horological masterpieces that will be studied and admired for decades, if not centuries, to come.", Image = "greubelforsey.png" },
               
                new Brand { Name = "Rolex", Description = "Rolex is arguably the world’s most recognized luxury watchmaker, a name synonymous with prestige, precision, and enduring quality. Founded in 1905 by Hans Wilsdorf, Rolex pioneered many of modern horology’s milestones – from creating the first waterproof wristwatch, the Oyster, in 1926 to introducing the first self-winding mechanism with a Perpetual rotor in 1931. This heritage of innovation established Rolex as a beacon of excellence in mechanical watchmaking. Each Rolex timepiece reflects a legacy of craftsmanship, built for reliability and accuracy that have been proven in the most demanding conditions, from the depths of the ocean to the summits of Everest. Over the decades, Rolex’s collections have produced some of the most iconic automatic watches in history. Models like the Submariner dive watch, the Daytona chronograph, and the GMT-Master have transcended their tool-watch origins to become cultural legends. The Datejust, introduced in 1945, set a new standard as the first wristwatch to automatically change the date, exemplifying the brand’s blend of innovation and timeless style. Such designs are instantly recognizable, often imitated but never equaled. Today, Rolex continues to uphold its heritage by crafting every movement in-house and subjecting each watch to rigorous chronometer testing. The result is a collection of refined mechanical timepieces that marry technical prowess with enduring elegance – an investment in lasting luxury for the discerning collector.", Image = "rolex.png" },
               
                new Brand { Name = "Omega", Description = "Omega is a Swiss luxury watch brand celebrated for its pioneering spirit and timeless quality – a name that resonates from ocean depths to outer space. Founded in 1848 by Louis Brandt, Omega grew from a small workshop into an industry leader by consistently blending innovation with classic design. By the early 20th century, Omega’s dedication to precision had earned it a role as official timekeeper for major events; notably, Omega has been the trusted timekeeper of the Olympic Games since 1932. Omega’s legacy in automatic/mechanical watchmaking is richly illustrated by its achievements: it was Omega timepieces that accompanied British airmen in WWI for reliability, and famously, an Omega Speedmaster chronograph that became the first watch worn on the Moon during the Apollo 11 mission in 1969. This adventurous ethos – coupled with relentless technological refinement, such as the development of the co-axial escapement for improved accuracy and longevity – has cemented Omega’s reputation for excellence. Omega’s collection showcases a balance of robust engineering and elegant design. The Speedmaster “Moonwatch”, immortalized by NASA, remains a hand-wound mechanical icon cherished by collectors for its storied past and enduring, functional styling. The Seamaster line, dating to 1948, embodies Omega’s maritime heritage and includes famed diving models like the Seamaster 300 and the Seamaster Diver 300M – known to many as James Bond’s watch of choice – combining sporty durability with sophisticated looks. Meanwhile, the De Ville and Constellation families highlight Omega’s dressier side, often featuring chronometer-rated movements and refined finishing for the cosmopolitan wearer. Across all models, Omega’s commitment to mechanical watchmaking shines. The brand has invested deeply in its in-house calibers, incorporating cutting-edge materials like silicon balance springs and achieving master chronometer certification for high precision under magnetic resistance. Yet, these technical feats never overshadow the watches’ wearability and style. Omega timepieces manage to feel both classic and contemporary, making them equally suited to adventurous souls and boardroom executives. For high-end shoppers at Tourbillon, Omega offers the confidence of a watch with proven performance and an illustrious heritage – a symbol of innovation, reliability, and universal sophistication on the wrist.", Image = "omega.png" },
               
                new Brand { Name = "Grand Seiko", Description = "Grand Seiko embodies the zenith of Japanese watchmaking, a brand defined by its pursuit of perfection, minimalist elegance, and relentless innovation in mechanical timekeeping. Established in 1960 as a high-end division of Seiko, Grand Seiko was born from a challenge: to craft the “ideal watch” that could rival – and even surpass – the finest Swiss chronometers. From the beginning, Grand Seiko timepieces have been distinguished by their exceptional precision, robust construction, and a distinctly Japanese aesthetic that draws on nature and simplicity. The brand’s philosophy of monozukuri (craftsmanship) is evident in every detail: cases are polished by hand using the Zaratsu technique to achieve distortion-free mirror surfaces, dials often feature subtle textures and patterns inspired by Japan’s seasons, and indexes and hands are diamond-cut to razor sharpness for both beauty and legibility. These elements together create an understated yet luxurious look that is uniquely Grand Seiko – restrained, radiant, and imbued with meaning. At the heart of Grand Seiko is an array of technically superb movements. The brand offers both traditional high-beat mechanical calibers (ticking at 36,000 vibrations per hour for greater accuracy) and the innovative Spring Drive movements, which marry a mechanical gear train with an electronically regulated glide wheel for remarkable precision and an utterly smooth sweeping seconds hand. (Spring Drive is a hallmark Grand Seiko invention, achieving quartz-level accuracy while maintaining the soul of a mechanical watch – a true testament to the brand’s inventive spirit.) Grand Seiko’s dedication to performance was proven in the 1960s when its chronometers repeatedly won or placed top in international observatory trials, announcing to the world that Japanese watchmaking could stand with the best. Today’s collections – the Heritage, Elegance, and Sport series – showcase the breadth of Grand Seiko’s artistry. In the Heritage line, one finds classic designs like the famous “Snowflake” (with its silvery, textured dial reminiscent of fresh snow) that exemplify purity and craftsmanship. The Sport models add contemporary flair and durability (diving watches, GMTs, etc.), while still finished to an immaculate standard. Despite their technical sophistication, Grand Seiko watches have a meditative simplicity in use – they are meant to be everyday watches that elevate the everyday experience. For the luxury consumer used to Swiss names, Grand Seiko offers something refreshingly different: a quiet confidence, an authenticity born of cultural pride, and a product whose quality – in finishing, accuracy, and durability – genuinely rivals anything in the world. To wear a Grand Seiko is to appreciate subtle luxury, where every surface and mechanism has been thoughtfully refined by masters of their craft, resulting in a timepiece that resonates with both precision and poetry.", Image = "grandseiko.png" },

                new Brand { Name = "IWC Schaffhausen", Description = "IWC Schaffhausen is a Swiss watchmaker renowned for marrying engineering excellence with horological heritage. Founded in 1868 by American watchmaker Florentine Ariosto Jones, IWC (short for “International Watch Company”) established itself in Schaffhausen, Switzerland – far from the country’s traditional watch hubs – to fuse advanced production techniques with Swiss craftsmanship. This pioneering spirit lives on in IWC’s meticulous mechanical timepieces. Every IWC watch reflects the brand’s credo of “Probus Scafusia” (good, solid craftsmanship from Schaffhausen), exemplifying precision, reliability, and understated refinement. From the early 20th century, IWC built a legacy of automatic movements and robust calibers that appealed to explorers, pilots, and innovators alike, emphasizing function without sacrificing elegance. IWC’s legacy is perhaps best illustrated by its iconic collections. The Portugieser (Portuguese) line, born in the 1930s, epitomizes clean, nautical-inspired design and superb automatic movements – a dress watch of timeless grace. Equally legendary are IWC’s Pilot’s Watches, dating back to the 1930s and 1940s when they supplied aviator chronometers; the Big Pilot and Mark series exemplify clarity and durability rooted in those early cockpit instruments. Over the years, IWC’s inventive streak led to use of advanced materials (such as pioneering titanium cases in the 1980s) and complex complications like perpetual calendars and chronographs, all executed with a distinctly utilitarian luxury. Today, as part of the Richemont group, IWC remains a favorite of aficionados who value its blend of Swiss precision and a bold, instrument-style aesthetic. Whether it’s a classic dress watch or a modern pilot’s chronograph, IWC watches carry an aura of technical excellence honed over a century and a half of fine watchmaking.", Image = "iwc.png" },
               
                new Brand { Name = "Frederique Constant", Description = "Frederique Constant is a relatively young marque in the luxury watch world, yet it has swiftly made its mark by championing classic Swiss watchmaking traditions at an accessible luxury price point. Founded in 1988 by Aletta and Peter Stas in Geneva, this independent brand (now part of the Citizen Group) was built on a vision of “accessible luxury” – creating elegant mechanical timepieces that offer exceptional value without compromising on quality or heritage. The very name “Frederique Constant” is a combination of the founders’ great-grandparents’ names, underscoring the personal legacy and family passion behind the brand’s inception. In just a few decades, Frederique Constant has developed an impressive in-house capability: the company designs, produces, and assembles its movements internally at its Plan-les-Ouates manufacture. It has introduced over 30 in-house calibers – including innovations like tourbillon escapements, perpetual calendars, and worldtimers – feats that demonstrate a serious commitment to mechanical watchmaking. This dedication is remarkable given the brand’s youth and price segment, and it highlights a core part of Frederique Constant’s appeal: bringing fine watchmaking – often seen as the domain of centuries-old maisons – to a broader audience of connoisseurs and enthusiasts. Frederique Constant watches are characterized by their timeless, genteel design and reliable Swiss mechanics. The brand’s aesthetic leans toward the classical: think clean roman numeral dials, guilloché patterns, and refined case silhouettes in its signature Classics collection. One of its early claims to fame was the “Heart Beat” design, which introduced an aperture on the dial to expose the beating balance wheel – a charming reminder of the mechanical heart within, and a statement celebrating transparency and authenticity in an age when quartz watches dominated (the Heart Beat became something of a Frederique Constant signature in the 1990s). In recent years, standout models like the Slimline Moonphase Manufacture have won praise for offering complications (e.g. moonphase and date) with in-house automatic movements at a fraction of the cost of established competitors. Similarly, the Classic Worldtimer showcases the brand’s global perspective, presenting world time functionality with an in-house caliber and beautiful globe motif dial. While keeping its prices comparatively attainable, Frederique Constant ensures each piece is solidly built – employing decorated movements visible through sapphire casebacks, and often adding touches like blued screws or perlage finishing. The tone is understated and elegant, making these watches versatile for daily wear or more formal occasions. For Tourbillon’s high-end shoppers, Frederique Constant offers a unique proposition: the charm and legitimacy of Swiss mechanical watch heritage presented in a refined, unpretentious manner. It’s an ideal choice for those who appreciate tradition and craftsmanship, but also value modern inclusivity in the luxury watch space – a fine Geneva-made timepiece that doesn’t require an inheritance to own, yet still delights in its detailing and performance.", Image = "frederiqueconstant.png" }
            };

            context.Brands.AddRange(brands);
            context.SaveChanges();
        }
    }
}
